import{_ as l,r as a,o as r,c as n,b as s,d as t,e,f as p,a as o}from"./app-31c067ee.js";const c={},d=t("h2",{id:"jdk-安装及配置环境变量",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#jdk-安装及配置环境变量","aria-hidden":"true"},"#"),e(" JDK 安装及配置环境变量")],-1),h=t("p",null,"因为 Gitblit 需要 JDK，所以需要配置 java 环境。在 java 官网下载的最新 JDK 是 13.0.0，经过我的测试发现会报错。所以改成了 JDK8.0，之后就可以正常运行了。",-1),g={href:"https://pan.baidu.com/s/1N1Q-pp21WkD32g371gwqOg",target:"_blank",rel:"noopener noreferrer"},b=o('<h3 id="配置-jdk-环境变量" tabindex="-1"><a class="header-anchor" href="#配置-jdk-环境变量" aria-hidden="true">#</a> 配置 JDK 环境变量</h3><p>配置如下，<strong>“我的电脑”-右键-“属性”-（左侧）高级系统设置-（弹窗右下角）环境变量配置，</strong> 窗口上方是用户变量，下方是系统变量，变量都配置在用户变量里！</p><blockquote><p>创建 JAVA_HOME，值是你的刚刚 jdk 的安装目录，比如 C:\\Program Files (x86)\\Java\\jdk1.8.0_101</p></blockquote><blockquote><p>创建 CLASS_PATH，值 .;%JAVA_HOME%\\lib\\dt.jar;%JAVA_HOME%\\lib\\tools.jar （注意最前面有一点）</p></blockquote><blockquote><p>编辑 PATH，把值放到最前边　.;%JAVA_HOME%\\bin;%JAVA_HOME%\\jre\\bin;</p></blockquote><p><img src="https://s2.loli.net/2021/12/16/xGCujRT7kILFP2g.png" alt="var.jpg"></p><h3 id="检查安装和配置情况" tabindex="-1"><a class="header-anchor" href="#检查安装和配置情况" aria-hidden="true">#</a> 检查安装和配置情况</h3><p>在命令行窗口中，输入以下两行命令</p><p><img src="https://s2.loli.net/2021/12/16/v59WchJLN3HBDbZ.png" alt="java.png"></p><h2 id="gitblit-的获取" tabindex="-1"><a class="header-anchor" href="#gitblit-的获取" aria-hidden="true">#</a> Gitblit 的获取</h2>',10),u={href:"http://www.gitblit.com/",target:"_blank",rel:"noopener noreferrer"},m=t("code",null,"D:\\Git\\gitblit\\gitblit-1.8.0",-1),_=o('<p><img src="https://s2.loli.net/2021/12/16/ThXpwiol2xAQB5z.png" alt="gitblitcom.png"></p><h2 id="创建-git-服务器资料存储文件夹" tabindex="-1"><a class="header-anchor" href="#创建-git-服务器资料存储文件夹" aria-hidden="true">#</a> 创建 Git 服务器资料存储文件夹</h2><p>创建文件夹为：<code>D:\\Git\\GitRepository</code></p><p><img src="https://s2.loli.net/2021/12/16/p9UuNlIP2OfbvsH.png" alt="gitfolder.png"></p><h2 id="配置-gitblit-属性" tabindex="-1"><a class="header-anchor" href="#配置-gitblit-属性" aria-hidden="true">#</a> 配置 Gitblit 属性</h2><p>1、找到<code>D:\\Git\\gitblit\\gitblit-1.8.0\\data\\defaults.properties</code>文件，我这里用“vscode”打开，你也可以用其它可编辑软件打开 将<code>git.repositoriesFolder = D:/Git/GitRepository</code> （我们前面创建的 Git 服务器的资料存储路径）</p><blockquote><p>注意! 其中的 D:\\Git\\GitRepository 中的”\\”一定要用”/“。</p></blockquote><p><img src="https://s2.loli.net/2021/12/16/IYRGOjhlX5A78HE.png" alt="repositoriesFolder.png"></p><p>2、找到 server.httpPort，设定 http 协议的端口号: 8442</p><p><img src="https://s2.loli.net/2021/12/16/3eF9K61UaBXdioO.png" alt="port.png"></p><p>3、找到 server.httpBindInterface，设定服务器的 IP 地址。这里就设定你电脑的 IP 地址：</p><blockquote><p>我电脑的 IP 地址为（192.168.1.101）</p></blockquote><p><img src="https://s2.loli.net/2021/12/16/Lr7y8l3cnUViOJq.png" alt="ip.png"></p><p>4、找到 server.httpsBindInterface，设定为 localhost</p><p><img src="https://s2.loli.net/2021/12/16/y9thkX5PRzijboI.png" alt="localhost.png"></p><p>5、 Ctr + s 保存文件，关闭。</p><h2 id="gitblit-批处理文件的修改与执行" tabindex="-1"><a class="header-anchor" href="#gitblit-批处理文件的修改与执行" aria-hidden="true">#</a> Gitblit 批处理文件的修改与执行</h2><p>进入文件夹 gitblit，找到 gitblit.cmd 文件，双击运行。</p><p><img src="https://s2.loli.net/2021/12/16/MJksE23Gm6u8qNz.png" alt="gitblitcmd.png"></p><p><img src="https://s2.loli.net/2021/12/16/bRJatO4cyjs9nlq.png" alt="gitblitcmdrun.png"></p><h2 id="设置以-windows-service-方式启动-gitblit" tabindex="-1"><a class="header-anchor" href="#设置以-windows-service-方式启动-gitblit" aria-hidden="true">#</a> 设置以 Windows Service 方式启动 Gitblit</h2><p>1、在文件夹 gitblit\\gitblit-1.8.0 中，找到 installService.cmd 文件，打开文件（我这里用记事本)。</p><p><img src="https://s2.loli.net/2021/12/16/gwSbPTvEmRLpBM8.png" alt="service.png"></p><p>2、用“记事本”打开，修改 ARCH</p><blockquote><p>32 位系统：<code>SET ARCH=x86</code></p><p>64 位系统：<code>SET ARCH=amd64 </code></p></blockquote><p>3、 添加 CD 为程序目录</p><blockquote><p><code>SET CD=D:\\Git\\gitblit</code>(你的实际目录)</p></blockquote><p><img src="https://s2.loli.net/2021/12/16/FzQtx3dUunj2WGg.png" alt="configservice.png"></p><p>4、修改 StartParams 里的启动参数，给空就可以了.</p><p><img src="https://s2.loli.net/2021/12/16/H8aw6KnsvSdTklZ.png" alt="startp.png"></p><p>5、Ctr + s 保存，关闭文件。</p><p>6、以管理员权限运行 installService.cmd。</p><p>在计算机服务里面查看有 gitblit 服务这一栏</p><blockquote><p>ps(如果要卸载这个服务,可以以管理员权限运行 CMD，在命令行中输入 sc delete gitblit 即可卸载)</p></blockquote><p><img src="https://s2.loli.net/2021/12/16/z6AZoxeHVgnXCad.png" alt="serviceinfo.png"></p><h2 id="在浏览器中查看-gitblit-服务器情况" tabindex="-1"><a class="header-anchor" href="#在浏览器中查看-gitblit-服务器情况" aria-hidden="true">#</a> 在浏览器中查看 gitblit 服务器情况：</h2><p>在浏览器地址栏中输入：<code>192.168.1.101:8442</code></p><p>可以看到安装成功，初始默认账号：admin 密码：admin</p><p><img src="https://s2.loli.net/2021/12/16/ehkjnDLpgN7mzvo.png" alt="show.png"></p>',39);function k(f,v){const i=a("ExternalLinkIcon");return r(),n("div",null,[s(" more "),d,h,t("blockquote",null,[t("p",null,[e("链接："),t("a",g,[e("https://pan.baidu.com/s/1N1Q-pp21WkD32g371gwqOg"),p(i)]),e(" 提取码：iuxw")])]),b,t("p",null,[e("传送门"),t("a",u,[e("http://www.gitblit.com/"),p(i)]),e("(Gitblit 官网)， 可以看到 1.8.0 版本，貌似还是 2016 年发布的。点击下载 windows 版本，下载后不用安装，直接解压，我这里是放在： "),m,e(" 路径下")]),_])}const x=l(c,[["render",k],["__file","gitblit.html.vue"]]);export{x as default};
